var b="url",c="收款单与冲账.html",d="generationDate",e=new Date(1781590702485.14),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="axhubclickvalue",s="page",t="packageId",u="60a3d6b1e46a42e9b86fdae8c1c683eb",v="type",w="Axure:Page",x="收款单与冲账",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="7d8af6d5ebe34b7e92ab4e8fbf847d43",E="label",F="关联单据",G="说明",H="<p><span>1.默认提示字“请选择客户”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.展示全部数据</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;客户资料]的客户</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.支持对&quot;客户名称&quot;的模糊搜索</span></p><p><span>3.右侧含“×”的快捷清除按钮</span></p><p><span>4.选中/清空：直接返回结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.针对&quot;客户&quot;列进行检索</span></p>",I="2",J="0bc651e804694207890ba146156715cf",K="(下拉列表)",L="<p><span>1.默认未选中，展示全部，提示字：记账状态</span></p><p><span>2.可选项：①已记账 ②未记账</span></p><p><span>3.右侧含“×”的快捷清除按钮</span></p><p><span>4.选中/清空：直接返回结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.针对&quot;记账状态&quot;列进行检索</span></p>",M="3",N="9e483419ad134cb788d66edca1a0671c",O="删除",P="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">校验逻辑</span></p><p><span>1.校验存在勾选，否则Toast提示：请至少勾选一行</span></p><p><span>2.校验勾选行的“制单人”为</span><span style=\"text-decoration:underline ;\">当前账户</span><span>，否则Toast提示：仅可对自己创建的单据进行删除</span></p><p><span>3.校验勾选行的状态</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">均为</span><span>“未记账”，否则Toast提示：已记账单据无法删除</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">通过校验，执行逻辑</span></p><p><span>1使用嵌套操作的弹窗框进行</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">二次确认</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.删除勾选单据</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.关闭当前确认弹窗</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.返回Toast提示：操作成功</span></p>",Q="4",R="cdba3797211642e2a6ba39d10cbea06c",S="记账",T="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">校验逻辑</span></p><p><span>1.校验存在勾选，否则Toast提示：请至少勾选一行</span></p><p><span>2.校验勾选行“记账状态”均为&quot;未记账&quot;，否则Toast提示：存在已记账单据( </span><span style=\"color:#0000FF;\">收款单号1，收款单号2，…</span><span>)</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.其中，</span><span style=\"color:#0000FF;\">XXX</span><span>为“记账状态”为&quot;已记账&quot;的</span><span style=\"text-decoration:underline ;\">收款编号</span></p><p><span>3.校验勾选行“客户”均在[财务管理系统&gt;&gt;应收管理：应收款期初]中存在记录，否则Toast提示：未设置期初的客户( </span><span style=\"color:#0000FF;\">客户名称1，客户名称2，…</span><span>)</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.其中，</span><span style=\"color:#0000FF;\">XXX</span><span>为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">未在</span><span>[财务管理系统&gt;&gt;应收管理：应收款期初]中产生记录的</span><span style=\"text-decoration:underline ;\">客户名称</span></p><p><span>4.若收款单的“收款类型”为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">&quot;期初&quot;</span><span>：对单据中的“已收余额”进行处理并校验 (防未记账到记账过程中单据内'已收余额'变更)</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.查询当前收款单对应“客户”在[财务管理系统&gt;&gt;应收管理：往来记账]中</span><span style=\"color:#8400FF;\">最后一条</span><span>的“已收余额”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.若该“客户”在往来记账中无记录，查询[财务管理系统&gt;&gt;应收管理：应收款期初]中该客户的“已收余额”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.将查询的结果赋给对应收款单的'已收余额'</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.校验该单据经处理后的'已收余额'与填写的'余额冲销'值大小</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c1.已收余额 ≥ 余额冲销 ：通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; c2.已收余额 &lt; 余额冲销 ：校验失败，并返回Toast提示：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">已收余额不足冲销，请变更后记账(</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">对应收款单号</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">)</span></p><p><span>5.若收款单的“收款类型”为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">&quot;结算收款&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.对单据中的“可用余额”进行处理并校验 (防未记账到记账过程中单据内'可用余额'变更)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.查询当前收款单对应“客户”在[财务管理系统&gt;&gt;应收管理：往来记账]中</span><span style=\"color:#8400FF;\">最后一条</span><span>的“已收余额”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1_1.若该“客户”在往来记账中无记录，查询[财务管理系统&gt;&gt;应收管理：应收款期初]中该客户的“已收余额”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a2.将查询的结果赋给对应收款单的'可用余额'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a3.校验该单据经处理后的'可用余额'与填写的'使用余额'值大小</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a3_1.可用余额 ≥ 使用余额 ：通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a3_2.可用余额 &lt; 使用余额 ：校验失败，并返回Toast提示：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">可用余额不足冲销使用，请变更后记账(</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">对应收款单号</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">)</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.校验单据内</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;text-decoration:underline ;\">收款清单</span><span>中“结算单号”的&quot;未收金额&quot;和</span><span style=\"text-decoration:underline ;\">当前于[财务管理系统&gt;&gt;应收管理：销售结算单]中</span><span>对应结算单的“未收金额”是否值仍一致(防未记账到记账过程中单据内单条应收结算单的'未付金额'变更到小于'合计收款'的值)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b1.一致：通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; b2.不一致：校验失败，并返回Toast提示：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">单据内应收金额产生变更，请于详情页确认收款金额后记账(</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">对应收款单号</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">)</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">通过校验，执行逻辑</span></p><p><span>使用嵌套操作的弹窗框进行</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">二次确认</span></p><p><span>对勾选数据行</span><span style=\"text-decoration:underline ;\">按&quot;收款日期&quot;顺序</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;text-decoration:underline ;\">依次</span><span>处理，逻辑如下</span></p><p><span>1.将勾选“收款单”数据进行处理</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.记账状态：置为'已记账'</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.记账人、记账时间：取当前操作人和操作时间记录</span></p><p><span>2.若收款单的“收款类型”为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">&quot;结算收款&quot;</span><span>，将“收款单”中包含的&quot;结算单号&quot;于[财务管理系统&gt;&gt;应收管理：销售结算单]中的相关数据进行处理</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.对“未收金额”重新赋值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>未收金额=</span><span style=\"color:#6D000E;\">原</span><span>未收金额-</span><span style=\"color:#6300BF;\">该收款单</span><span>针对该结算单对应行的</span><span style=\"text-decoration:underline ;\">合计收款</span></p><p><span>3.在[财务管理系统&gt;&gt;应收管理：往来记账]中对应生成数据</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.客户：取“收款单”对应的&quot;客户&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.关联单据：取“收款单”对应的&quot;收款编号&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.销售应收：按'0'传入</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; d.调整追加应收：按'0'传入</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; e.调整扣除应收：按'0'传入</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; f.收款金额：取“收款单”对应的&quot;收款金额&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; g.余额冲销：取“收款单”对应的&quot;余额冲销&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; h.末期应收：根据“收款类型”取值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; h1.收款类型==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">结算收款</span><span>：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期应收=</span><span style=\"color:#008080;\">客户上期</span><span>末期应收-</span><span style=\"color:#6300BF;\">该收款单</span><span>结算应收</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; h2.收款类型==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">期初</span><span>：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期应收=</span><span style=\"color:#008080;\">客户上期</span><span>末期应收-</span><span style=\"color:#6300BF;\">该收款单</span><span>合计金额</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; h3.收款类型==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">预收款</span><span>：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期应收=</span><span style=\"color:#008080;\">客户上期</span><span>末期应收</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; i.末期余额：根据“收款类型”取值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i1.收款类型==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">结算收款</span><span>：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期余额=</span><span style=\"color:#008080;\">客户上期</span><span>末期余额</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">-</span><span style=\"color:#6300BF;\">该收款单</span><span>使用余额</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">+</span><span style=\"color:#6300BF;\">该收款单</span><span>收款金额</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">-</span><span style=\"color:#6300BF;\">该收款单</span><span style=\"text-decoration:underline ;color:#6300BF;\">清单列</span><span>Σ本次收款</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i2.收款类型==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">期初</span><span>：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期余额=</span><span style=\"color:#008080;\">客户上期</span><span>末期余额</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">-</span><span style=\"color:#6300BF;\">该收款单</span><span>余额冲销</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i3.收款类型==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#6D000E;\">预收款</span><span>：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">新</span><span>末期余额=</span><span style=\"color:#008080;\">客户上期</span><span>末期余额</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">+</span><span style=\"color:#6300BF;\">该收款单</span><span>收款金额</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; j.操作人、操作时间：取当前操作人和操作时间记录</span></p><p><span>4.关闭当前确认弹窗</span></p><p><span>5.返回Toast提示：操作成功</span></p>",U="5",V="ff6c2e5d72304b239f0c2e0ebb0b4d2a",W="收款编号",X="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">未记账</span></p><p><span>1.</span><span style=\"color:#333333;\">类型为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">&quot;结算收款&quot;</span><span style=\"color:#333333;\">或</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">&quot;期初&quot;</span><span style=\"color:#333333;\">，</span><span>自动再次查询“已收余额”并覆盖</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.根据单据的“客户”再次查询该客户当前[财务管理系统&gt;&gt;应收管理：往来记账]最后一条的“已收余额”，若该客户未存在过往来记账，查询[财务管理系统&gt;&gt;应收管理：应收款期初]中该客户的“已收余额”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.直接将查询值覆盖至该单据该字段数据库的值，无须调用当前页【保存】</span></p><p><span>2.</span><span style=\"color:#333333;\">类型为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">&quot;结算收款&quot;</span><span>校验查询当前“客户”在[采购结算单]和[外发结算单]内是否存在“未付金额”＞0的结算单，与当前现有的“应收结算单”进行匹配</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.若查询到的“应收结算单”及对应“应收金额”均一致，不做提示</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.若查询到的“应收结算单”及对应“应收金额”存在差异，在内页【同步更新】按钮左侧展示提示字：结算应收被更新，请同步！</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">已记账</span></p><p><span>1.仅进入对应</span><span style=\"text-decoration:underline ;\">详情页</span><span>查看信息</span></p>",Y="6",Z="8eb70b3155954948b0ed8d651cfd629c",ba="收款备注",bb="<p><span>1.按宽度限制字数，多余字符使用'…'截断</span></p><p><span>2.鼠标移入：使用Tooltips展示全部</span></p>",bc="7",bd="ef8547127fcd4ac3a32414124d39c6a3",be="* 客户：",bf="<p><span>1.数据源：[基础数据系统&gt;&gt;客户资料]的客户</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.支持对&quot;客户名称&quot;的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.选中后仅返回&quot;客户名称&quot;至当前下拉域</span></p><p><span>2.切换“客户”选项后，重新查询其“未收款记账”</span></p>",bg="8",bh="ffcc6963390e4fe9af90bcaa2b200d77",bi="未记账收款：",bj="<p><span>1.取值：跟随选中的“客户”在[财务管理系统&gt;&gt;应收管理：收款单与冲账]中是否存在状态为“未记账”的收款单</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.不存在</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a1.固定为'</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">无</span><span>'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a2.黑色字体</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.存在</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b1.取对应&quot;收款编号&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b2.红色字体</span></p><p><span>2.每切换“收款单位”时对当前字段重新取值</span></p>",bk="9",bl="c7a36c155d1047de9868ce2433707b18",bm="收款类型：",bn="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">单选按钮</span></p><p><span>1.预收款 (</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">默认选中</span><span>)</span></p><p><span>2.期初</span></p>",bo="10",bp="9ab910b620c345ee806cd9c18b235e3b",bq="确认",br="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">校验逻辑</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.校验“客户”非空，否则Toast提示：请选择客户</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.校验选中的“客户”在[财务管理系统&gt;&gt;应收管理：应收款期初]中存在对应数据，否则Toast提示：该客户未设置期初，无法发起收款</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.校验当前“未记账收款”的值是否为‘无’</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; a.“未记账收款”为'无'：通过校验</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; b.“未记账收款”为具体&quot;收款单号&quot;：Toast提示“ </span><span style=\"font-family:'Nunito Sans Bold Oblique', 'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;font-style:oblique;\">存在未记账的收款单，请在原单据上操作</span><span style=\"font-family:'Nunito Sans Oblique', 'Nunito Sans', sans-serif;font-style:oblique;\">&nbsp; </span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">”</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">4.若“</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;color:#7B4D12;\">本次收款==期初</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">”，校验对应的'客户'在[财务管理系统&gt;&gt;应收管理：应收款期初]中“</span><span style=\"font-family:'Arial Negreta', 'Arial Normal', 'Arial', sans-serif;font-weight:700;\">期初应收＞0</span><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">”，否则Toast提示：该客户期初无应收，无须收款</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">通过校验，执行逻辑</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.根据选择的'收款类型'跳转至对应新增发起页</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; a.客户：按当前选择的“客户”填充</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; b.其它字段取值见内页对应批注</span></p>",bs="style",bt="baseStyle",bu="627587b6038d43cca051c114ac41ad32",bv="pageAlignment",bw="center",bx="fill",by="fillType",bz="solid",bA="color",bB=0xFFFFFFFF,bC="image",bD="imageAlignment",bE="near",bF="imageRepeat",bG="auto",bH="favicon",bI="sketchFactor",bJ="0",bK="colorStyle",bL="appliedColor",bM="fontName",bN="Applied Font",bO="borderWidth",bP="borderVisibility",bQ="borderFill",bR=0xFF797979,bS="cornerRadius",bT="cornerVisibility",bU="outerShadow",bV="on",bW=false,bX="offsetX",bY=5,bZ="offsetY",c